{
  "bdd_intent_contract": {
    "given": "A developer has submitted a new skill package via the `/skills/submit` endpoint. The skill package includes a `manifest.json` conforming to DECISION-021, declaring `plugin_id`, `version`, `runtime`, `permissions`, `dependencies`, and `SHA-256 checksum`. The system has a `SkillSecurityScanner` capable of static analysis, CVE checks, and permission audits, as per DECISION-028 and `marketplace/security.py`'s TODOs.",
    "when": "The `submit_skill` endpoint processes the incoming `SkillSubmission` payload.",
    "then": "The skill package artifact is successfully stored. An automated security scan is initiated using the `SkillSecurityScanner`. The output of this scan (ScanReport) is stored alongside the skill artifact for auditability. If the automated security scan passes, the skill is then queued for manual review. If the automated security scan fails (e.g., due to CVEs, disallowed permissions, or static analysis findings), the submission is rejected with a clear security failure status, and it is not queued for manual review. The skill is prevented from being listed in the marketplace until both the automated security scan and subsequent human approval are successfully completed."
  },
  "completeness_flags": {
    "missing_requirements": [
      "Detailed specification for the `ScanReport` data structure, including types of findings (CVE, static analysis, permission violation), severity, and remediation suggestions.",
      "Mechanism and location for storing the `ScanReport` in association with the skill artifact.",
      "Definition of the specific static analysis rules and tools to be employed.",
      "Definition of the CVE databases and scanning methodology to be used for dependency checks.",
      "Specification of the 'allowlist' for permissions (DECISION-021) and how it's enforced by the scanner.",
      "Error handling and notification mechanism for developers when a scan fails.",
      "Integration logic within `marketplace/submission_api.py` to invoke `SkillSecurityScanner.scan()` and process its result."
    ],
    "missing_nonfunctional": [
      "Performance requirements for the scanner (e.g., maximum acceptable scan time per skill).",
      "Scalability requirements for the scanning infrastructure to handle concurrent submissions.",
      "Security hardening of the scanner itself (e.g., sandboxing, resource limits).",
      "Audit logging for all scan attempts, results, and associated actions.",
      "Resilience and retry mechanisms for transient scanner failures."
    ]
  },
  "suggested_kpis": [
    {
      "metric": "Automated Scan Pass Rate",
      "target": "> 90%",
      "rationale": "Measures the effectiveness of the scanner and the quality of submitted skills. A high rate indicates developers are adhering to security guidelines or the scanner is well-tuned."
    },
    {
      "metric": "Average Scan Duration",
      "target": "< 5 minutes",
      "rationale": "Impacts developer experience and the overall throughput of the submission pipeline. Faster scans lead to quicker feedback."
    },
    {
      "metric": "False Positive Rate (Scanner)",
      "target": "< 2%",
      "rationale": "High false positives lead to developer frustration and increased manual review burden. A low rate indicates scanner accuracy."
    },
